import { useState, useRef, useEffect } from 'react';
import { m, AnimatePresence, LazyMotion, domMax } from 'framer-motion';
import { useMasteryStore } from '../store/masteryStore';
import {
  buildSystemPrompt, streamCompletion, stripProposedChanges,
  parseProposedChanges, resolveApiKey, fetchSessionRecap,
  fetchQuickTranslation
} from '../services/linaService';
import type { ProposedChange } from '../services/linaService';
import type { MasteryStatus } from '../types/mastery';

interface Props {
  onEndSession: () => void;
  isActive: boolean;
  pendingPrompt?: string | null;
  clearPrompt?: () => void;
  isSandboxMode: boolean;
}

interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  displayContent: string;
  raw?: string;
  proposedChanges?: ProposedChange[];
}

const STATUS_EMOJI: Record<MasteryStatus, string> = {
  not_started: '⬜',
  introduced:  '🔵',
  practicing:  '🟡',
  confident:   '🟢',
  mastered:    '✅',
};

const HISTORY_WINDOW = 10;
const SANDBOX_RESPONSE = '[SANDBOX MODE]: o toki! I am in offline testing mode. No API tokens are being used right now.';

export default function ChatSession({ onEndSession, isActive, pendingPrompt, clearPrompt, isSandboxMode }: Props) {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const [translateBubble, setTranslateBubble] = useState<{
    text: string;
    top: number;
    left: number;
    result?: string;
    loading?: boolean;
  } | null>(null);

  const vocabulary          = useMasteryStore(s => s.vocabulary);
  const updateVocabStatus   = useMasteryStore(s => s.updateVocabStatus);
  const updateConceptStatus = useMasteryStore(s => s.updateConceptStatus);
  const setLastUpdated      = useMasteryStore(s => s.setLastUpdated);
  const studentName         = useMasteryStore(s => s.studentName);
  const profile             = useMasteryStore(s => s.profile);
  const lore                = useMasteryStore(s => s.lore);

  const messagesEndRef  = useRef<HTMLDivElement>(null);
  const historyRef      = useRef<{ role: 'user' | 'assistant'; content: string }[]>([]);
  const sessionDeltasRef = useRef<ProposedChange[]>([]);

  useEffect(() => {
    if (isActive) messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isActive]);

  useEffect(() => {
    const handleGlobalClick = () => setTranslateBubble(null);
    window.addEventListener('mousedown', handleGlobalClick);
    return () => window.removeEventListener('mousedown', handleGlobalClick);
  }, []);

  const handleTextSelection = () => {
    const selection = window.getSelection();
    if (!selection || selection.isCollapsed) return;
    const text = selection.toString().trim();
    if (!text) return;
    setTimeout(() => {
      try {
        const range = selection.getRangeAt(0);
        const rects = range.getClientRects();
        if (rects.length === 0) return;
        const lastRect = rects[rects.length - 1];
        setTranslateBubble({ text, top: lastRect.top - 45, left: lastRect.left + (lastRect.width / 2) });
      } catch (err) { console.error('Selection error:', err); }
    }, 10);
  };

  const handleTranslateClick = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!translateBubble || translateBubble.loading) return;
    setTranslateBubble(prev => prev ? { ...prev, loading: true } : null);
    try {
      const key = resolveApiKey();
      const result = await fetchQuickTranslation(key, translateBubble.text);
      setTranslateBubble(prev => prev ? { ...prev, loading: false, result: result || 'Could not translate.' } : null);
    } catch (err) {
      setTranslateBubble(prev => prev ? { ...prev, loading: false, result: 'Error translating.' } : null);
    }
  };

  useEffect(() => {
    if (!isActive || !pendingPrompt) return;
    setMessages([]);
    setInput('');
    historyRef.current = [];
    sessionDeltasRef.current = [];
    const key = resolveApiKey();
    if (key || isSandboxMode) { sendToLina(pendingPrompt, key); }
    clearPrompt?.();
  }, [isActive, pendingPrompt]);

  async function handleEndSession() {
    const deltas = sessionDeltasRef.current;
    if (deltas.length === 0 || isSandboxMode) { onEndSession(); return; }
    for (const change of deltas) {
      if (change.type === 'vocab') updateVocabStatus(change.id, change.newStatus);
      else updateConceptStatus(change.id, change.newStatus);
    }
    setLastUpdated(new Date().toLocaleDateString());
    const key = resolveApiKey();
    const recapId = crypto.randomUUID();
    setMessages(prev => [...prev, { id: recapId, role: 'assistant', displayContent: '· · ·' }]);
    setIsLoading(true);
    const recap = await fetchSessionRecap(key, deltas);
    setMessages(prev => prev.map(msg => msg.id === recapId ? { ...msg, displayContent: recap } : msg));
    setIsLoading(false);
    await new Promise(r => setTimeout(r, 2200));
    sessionDeltasRef.current = [];
    onEndSession();
  }

  async function sendToLina(txt: string, overrideKey?: string) {
    if (isLoading || !txt.trim()) return;
    if (!isSandboxMode && !resolveApiKey(overrideKey)) return;
    setIsLoading(true);
    setInput('');
    setMessages(prev => [...prev, { id: crypto.randomUUID(), role: 'user', displayContent: txt }]);
    historyRef.current.push({ role: 'user', content: txt });
    const assistantId = crypto.randomUUID();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', displayContent: '', raw: '' }]);
    if (isSandboxMode) {
      setMessages(prev => prev.map(msg => msg.id === assistantId ? { ...msg, displayContent: SANDBOX_RESPONSE, raw: SANDBOX_RESPONSE } : msg));
      historyRef.current.push({ role: 'assistant', content: SANDBOX_RESPONSE });
      setIsLoading(false);
      return;
    }
    try {
      const key = resolveApiKey(overrideKey);
      const state = useMasteryStore.getState();
      const activeCurriculum = state.activeCurriculumId ? state.curriculums.find(c => c.id === state.activeCurriculumId) : null;
      const activeModule = activeCurriculum && state.activeModuleId ? activeCurriculum.modules.find(m => m.id === state.activeModuleId) : null;
      const sys = buildSystemPrompt(state.vocabulary, state.concepts, state.studentName, JSON.stringify(state.lore), activeCurriculum?.title, activeModule?.title);
      const windowedHistory = historyRef.current.slice(-HISTORY_WINDOW);
      let full = '';
      for await (const chunk of streamCompletion(key, sys, windowedHistory)) {
        full += chunk;
        setMessages(prev => prev.map(msg => msg.id === assistantId ? { ...msg, displayContent: stripProposedChanges(full), raw: full } : msg));
      }
      const changes = parseProposedChanges(full);
      if (changes && changes.length > 0) {
        sessionDeltasRef.current.push(...changes);
        setMessages(prev => prev.map(msg => msg.id === assistantId ? { ...msg, proposedChanges: changes } : msg));
      }
      historyRef.current.push({ role: 'assistant', content: full });
    } catch (e) {
      console.error(e);
      setMessages(prev => prev.map(msg => msg.id === assistantId ? { ...msg, displayContent: "pakala!" } : msg));
    } finally { setIsLoading(false); }
  }

  return (
    <LazyMotion features={domMax}>
      <motion.div
        className="side-panel chat-drawer"
        initial={{ x: '100%' }}
        animate={{ x: 0 }}
        exit={{ x: '100%' }}
        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
        onMouseUp={handleTextSelection}
        onTouchEnd={handleTextSelection}
      >
        <header className="side-panel-header">
          <button onClick={handleEndSession} className="btn-back"><span>✕</span> CLOSE</button>
          <h2 style={{ marginLeft: '16px', fontSize: '0.9rem', fontWeight: 900, letterSpacing: '0.15em', color: 'var(--gold)' }}>NEURAL LINK</h2>
        </header>

        {translateBubble && (
          <div onMouseDown={e => e.stopPropagation()} style={{ position: 'fixed', top: translateBubble.top, left: translateBubble.left, transform: 'translateX(-50%)', zIndex: 3000, background: '#222', border: '1px solid #444', borderRadius: '4px', padding: '8px 12px', boxShadow: '0 4px 12px rgba(0,0,0,0.5)', fontSize: '0.8rem', color: 'white', minWidth: '100px', textAlign: 'center' }}>
            {translateBubble.result ? <div style={{ lineHeight: '1.4' }}>{translateBubble.result}</div> : <button onClick={handleTranslateClick} style={{ background: 'var(--gold)', border: 'none', borderRadius: '2px', color: 'black', padding: '4px 8px', fontWeight: 900, cursor: 'pointer', fontSize: '0.7rem' }}>{translateBubble.loading ? '...' : 'TRANSLATE'}</button>}
          </div>
        )}

        <div style={{ flex: 1, overflowY: 'auto', padding: '20px' }}>
          {isSandboxMode && <div style={{ marginBottom: '12px', padding: '8px', border: '1px solid var(--gold)', borderRadius: '2px', fontSize: '0.7rem', color: 'var(--gold)', textAlign: 'center' }}>OFFLINE PROTOCOL ACTIVE</div>}
          {messages.map((msg) => (
            <div key={msg.id} style={{ marginBottom: '24px', textAlign: msg.role === 'user' ? 'right' : 'left' }}>
              <div style={{ color: 'var(--gold)', fontSize: '0.6rem', marginBottom: '4px', fontWeight: 900, letterSpacing: '0.1em' }}>{msg.role === 'assistant' ? 'LINA' : 'USER'}</div>
              <div style={{ background: msg.role === 'assistant' ? 'rgba(255,255,255,0.03)' : 'rgba(255, 191, 0, 0.1)', padding: '12px', borderRadius: '2px', border: '1px solid var(--border)', color: 'white', display: 'inline-block', textAlign: 'left', maxWidth: '90%', fontSize: '0.9rem', lineHeight: '1.5' }}>{msg.displayContent || (isLoading && msg.role === 'assistant' ? '...' : '')}</div>
              {msg.proposedChanges && msg.proposedChanges.map((c, i) => <div key={i} style={{ marginTop: '4px', fontSize: '0.65rem', color: 'var(--gold)', fontWeight: 700 }}>+ CALIBRATING: {c.id} → {c.newStatus}</div>)}
            </div>
          ))}
          <div ref={messagesEndRef} />
        </div>

        <div style={{ padding: '16px', background: 'rgba(5,5,5,0.5)', borderTop: '1px solid var(--border)', display: 'flex', gap: '8px' }}>
          <input value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && sendToLina(input)} placeholder="Input command..." style={{ flex: 1, background: 'rgba(255,255,255,0.03)', border: '1px solid var(--border)', borderRadius: '2px', padding: '12px', color: 'white', outline: 'none', fontSize: '0.9rem' }} />
          <button onClick={() => sendToLina(input)} disabled={isLoading} style={{ background: 'var(--gold)', border: 'none', borderRadius: '2px', padding: '0 20px', color: 'black', fontWeight: 900, cursor: 'pointer', opacity: isLoading ? 0.6 : 1 }}>{isLoading ? '...' : 'EXEC'}</button>
        </div>
      </motion.div>
    </LazyMotion>
  );
}

/* src/components/MasteryGrid.tsx */
import { useState, useRef, useEffect } from 'react';
import { useMasteryStore } from '../store/masteryStore';
import VocabCard from './VocabCard';
import WordDetailDrawer from './WordDetailDrawer';
import { fetchSentenceSuggestions, fetchQuickTranslation, resolveApiKey, buildOfflineTranslation, stringifyUserContext } from '../services/linaService';
import type { MasteryStatus, VocabWord } from '../types/mastery';

interface Props {
  onAskLina: (p: string) => void;
  onSaved?: (phraseId: string) => void;
  isSandboxMode: boolean;
  activeFilter: MasteryStatus | null;
  sortMode: string;
  sortDirection: 'asc' | 'desc';
  posFilter: string;
  setSortMode: (mode: any) => void;
  setSortDirection: (dir: any) => void;
  setPosFilter: (pos: string) => void;
}

const STATUS_RANK: Record<MasteryStatus, number> = {
  not_started: 0, introduced: 1, practicing: 2, confident: 3, mastered: 4
};

export default function MasteryGrid({
  onAskLina, onSaved, isSandboxMode, activeFilter, sortMode, sortDirection, posFilter,
  setSortMode, setSortDirection, setPosFilter
}: Props) {
  const { vocabulary, savePhrase, profile, lore } = useMasteryStore();
  const [selectedWords, setSelectedWords] = useState<string[]>([]);
  const [drawerId, setDrawerId] = useState<string | null>(null);
  const [magneticSuggestions, setMagneticSuggestions] = useState<string[]>([]);
  const [translation, setTranslation] = useState<string | null>(null);
  const [isAutoTranslating, setIsAutoTranslating] = useState(false);
  const [savedConfirm, setSavedConfirm] = useState(false);

  const confirmTimer  = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    setTranslation(null);
    setIsAutoTranslating(false);
    if (confirmTimer.current) { clearTimeout(confirmTimer.current); confirmTimer.current = null; }
    setSavedConfirm(false);

    if (selectedWords.length === 0) { setMagneticSuggestions([]); return; }

    if (isSandboxMode) {
      setTranslation(buildOfflineTranslation(selectedWords, vocabulary));
      setMagneticSuggestions([]);
      return;
    }

    const apiKey = resolveApiKey();
    if (!apiKey) {
      setTranslation(buildOfflineTranslation(selectedWords, vocabulary));
      setMagneticSuggestions([]);
      return;
    }

    setIsAutoTranslating(true);
    let active = true;
    const timer = setTimeout(async () => {
      const uniqueWords = [...new Set(selectedWords)];
      const userContext = stringifyUserContext(profile, lore);
      const [transResult, suggResults] = await Promise.all([
        fetchQuickTranslation(apiKey, selectedWords.join(' ')),
        selectedWords.length >= 2
          ? fetchSentenceSuggestions(apiKey, uniqueWords, userContext)
          : Promise.resolve([]),
      ]);
      if (active) {
        setTranslation(transResult ?? buildOfflineTranslation(selectedWords, vocabulary));
        setMagneticSuggestions(suggResults);
        setIsAutoTranslating(false);
      }
    }, 900);

    return () => { active = false; clearTimeout(timer); setIsAutoTranslating(false); };
  }, [selectedWords, isSandboxMode, profile, lore, vocabulary]);

  const handleCardClick = (word: VocabWord) => {
    if (selectedWords.length === 0) {
      setDrawerId(word.id);
    } else {
      setSelectedWords(prev => [...prev, word.word]);
    }
  };

  const handleCardLongPress = (word: VocabWord) => {
    if (selectedWords.length > 0) {
      setSelectedWords(prev => [...prev, word.word]);
    } else {
      setDrawerId(word.id);
    }
  };

  const handleSave = () => {
    const sentence = selectedWords.join(' ');
    savePhrase({ id: sentence, tp: sentence, en: translation ?? '', notes: '' });
    if (confirmTimer.current) clearTimeout(confirmTimer.current);
    setSavedConfirm(true);
    confirmTimer.current = setTimeout(() => {
      setSavedConfirm(false);
      confirmTimer.current = null;
      setSelectedWords([]);
      onSaved?.(sentence);
    }, 800);
  };

  const displayed = vocabulary
    .filter(w => posFilter === 'All' || w.partOfSpeech.toLowerCase().includes(posFilter.toLowerCase()))
    .sort((a, b) => {
      if (sortMode === 'status') {
        const diff = STATUS_RANK[a.status] - STATUS_RANK[b.status];
        return sortDirection === 'asc' ? diff : -diff;
      }
      if (sortMode === 'length') {
        const diff = a.word.length - b.word.length;
        return sortDirection === 'asc' ? diff : -diff;
      }
      if (sortMode === 'partOfSpeech') {
        const diff = a.partOfSpeech.localeCompare(b.partOfSpeech);
        return sortDirection === 'asc' ? diff : -diff;
      }
      if (sortMode === 'useCount') {
        const diff = (a.frequencyRank ?? 999) - (b.frequencyRank ?? 999);
        return sortDirection === 'asc' ? diff : -diff;
      }
      const valA = a.word.toLowerCase();
      const valB = b.word.toLowerCase();
      return sortDirection === 'asc' ? valA.localeCompare(valB) : valB.localeCompare(valA);
    });

  return (
    <div
      className="mastery-grid-container"
      style={{ paddingBottom: selectedWords.length > 0 ? '240px' : undefined }}
      onClick={() => { if (selectedWords.length > 0) setSelectedWords([]); }}
    >
      <div className="grid-toolbar">
        <select value={sortMode} onChange={(e) => setSortMode(e.target.value)} className="sort-select">
          <option value="alphabetical">A → Z</option>
          <option value="status">Mastery Level</option>
          <option value="length">Word Length</option>
          <option value="partOfSpeech">Part of Speech</option>
          <option value="useCount">Most Used</option>
        </select>
        <button
          onClick={(e) => { e.stopPropagation(); setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc'); }}
          className="btn-toggle"
          style={{ flex: 'none', width: '42px' }}
        >
          {sortDirection === 'asc' ? '↑' : '↓'}
        </button>
      </div>

      <div className="mastery-grid__cards">
        {displayed.map((word) => {
          const positions: number[] = [];
          selectedWords.forEach((w, i) => { if (w === word.word) positions.push(i + 1); });
          const isSelected = positions.length > 0;
          const isFilterDimmed = activeFilter && word.status !== activeFilter;

          return (
            <div
              key={word.id}
              className="grid-item-wrapper"
              style={{
                position: 'relative',
                opacity: (selectedWords.length > 0 && !isSelected) || isFilterDimmed ? 0.3 : 1,
                cursor: 'pointer',
                transition: 'opacity 0.25s ease',
              }}
              onClick={(e) => e.stopPropagation()}
            >
              <VocabCard 
                word={word} 
                onClick={handleCardClick}
                onLongPress={handleCardLongPress}
              />

              {positions.length > 0 && (
                <div style={{
                  position: 'absolute',
                  top: 3,
                  right: 3,
                  display: 'flex',
                  flexWrap: 'wrap',
                  gap: '2px',
                  justifyContent: 'flex-end',
                  maxWidth: '64px',
                  pointerEvents: 'none',
                }}>
                  {positions.map(pos => (
                    <span
                      key={pos}
                      style={{
                        background: '#3b82f6',
                        color: 'white',
                        borderRadius: '50%',
                        width: '16px',
                        height: '16px',
                        fontSize: '0.58rem',
                        fontWeight: 800,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        lineHeight: 1,
                        boxShadow: '0 1px 3px rgba(0,0,0,0.6)',
                      }}
                    >
                      {pos}
                    </span>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {selectedWords.length > 0 && (
        <div className="builder-panel" onClick={(e) => e.stopPropagation()}>
          <div className="builder-content">
            <div style={{
              minHeight: '20px',
              color: isAutoTranslating ? '#444' : '#64748b',
              fontSize: '0.78rem',
              fontStyle: 'italic',
              marginBottom: '12px',
              letterSpacing: '0.01em',
            }}>
              {isAutoTranslating ? '· · ·' : (translation ?? '')}
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '10px', gap: '8px' }}>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px', flex: 1 }}>
                {selectedWords.map((w, idx) => {
                  const vocab = vocabulary.find(v => v.word === w);
                  const meaning = vocab?.meanings?.split(',')[0].trim() || '';
                  return (
                    <div key={idx} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                      <div style={{ fontSize: '0.6rem', color: '#888', textTransform: 'uppercase', fontWeight: 700, marginBottom: '2px' }}>{meaning}</div>
                      <div style={{ color: 'white', fontSize: '1.2rem', fontWeight: 'bold' }}>{w}</div>
                    </div>
                  );
                })}
              </div>
              <button
                onClick={() => setSelectedWords(prev => prev.slice(0, -1))}
                className="btn-toggle"
                style={{ flex: 'none', width: '34px', height: '34px', padding: 0, fontSize: '0.9rem', marginBottom: '4px' }}
                title="Remove last word"
              >⌫</button>
            </div>

            {magneticSuggestions.length > 0 && (
              <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap', marginBottom: '12px' }}>
                {magneticSuggestions.map((s, i) => (
                  <button
                    key={i}
                    className="suggestion-pill"
                    onClick={() => { onAskLina(`Let's practice this: "${s}"`); setSelectedWords([]); }}
                  >
                    {s}
                  </button>
                ))}
              </div>
            )}

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '8px' }}>
              <button
                onClick={() => { onAskLina(`toki jan Lina! Let's work on: "${selectedWords.join(' ')}" — is this correct Toki Pona?`); setSelectedWords([]); }}
                className="btn-review"
                style={{ margin: 0, fontSize: '0.72rem', padding: '10px 4px' }}
              >
                ASK JAN LINA
              </button>
              <button
                onClick={() => setSelectedWords([])}
                className="btn-review"
                style={{ margin: 0, fontSize: '0.72rem', padding: '10px 4px', background: '#374151' }}
              >
                CLEAR
              </button>
              <button
                onClick={handleSave}
                className="btn-review"
                style={{ margin: 0, fontSize: '0.72rem', padding: '10px 4px', background: savedConfirm ? '#10b981' : undefined }}
              >
                {savedConfirm ? 'SAVED ✓' : 'SAVE'}
              </button>
            </div>
          </div>
        </div>
      )}

      <WordDetailDrawer
        isOpen={!!drawerId}
        word={drawerId ? vocabulary.find(v => v.id === drawerId) ?? null : null}
        onClose={() => setDrawerId(null)}
        onAskLina={onAskLina}
        isSandboxMode={isSandboxMode}
      />
    </div>
  );
}

