import { useState } from 'react';
import { motion } from 'framer-motion';
import { useMasteryStore } from '../store/masteryStore';
import { useAuthStore } from '../store/authStore';
import type { LoreCategory } from '../types/mastery';

interface Props {
  isOpen: boolean;
  onClose: () => void;
}

export default function UserProfilePanel({ onClose }: Props) {
  const { profile, updateProfile, lore, addLore, deleteLore, currentStreak, savedPhrases, getStatusSummary, clearLocalData } = useMasteryStore();
  const { logout, setUser, signIn, isGuest, user } = useAuthStore();

  const [loreCategory, setLoreCategory] = useState<LoreCategory>('Work');
  const [loreDetail, setLoreDetail] = useState('');

  const summary = getStatusSummary();
  const totalLearned = summary.introduced + summary.practicing + summary.confident + summary.mastered;

  const handleAddLore = () => {
    if (!loreDetail.trim()) return;
    addLore(loreCategory, loreDetail);
    setLoreDetail('');
  };

  return (
    <motion.div
      className="side-panel"
      initial={{ x: '100%' }}
      animate={{ x: 0 }}
      exit={{ x: '100%' }}
      transition={{ type: 'spring', damping: 25, stiffness: 200 }}
    >
      <header className="side-panel-header">
        <button onClick={onClose} className="btn-back">
          <span>✕</span> CLOSE
        </button>
        <h2 style={{ marginLeft: '16px', fontSize: '0.9rem', fontWeight: 900, letterSpacing: '0.15em', color: 'var(--gold)' }}>USER PROFILE</h2>
      </header>

      <div className="side-panel-content">
        <div style={{ marginBottom: '32px', textAlign: 'center' }}>
          <div style={{ 
            width: '80px', height: '80px', background: 'var(--surface)', 
            borderRadius: '2px', display: 'flex', alignItems: 'center', 
            justifyContent: 'center', fontSize: '2.5rem', margin: '0 auto 16px auto',
            border: '1px solid var(--gold)',
            boxShadow: '0 0 15px rgba(255, 191, 0, 0.1)'
          }}>
            {user?.photoURL ? <img src={user.photoURL} style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : '👤'}
          </div>
          <h2 style={{ margin: 0, color: 'white', fontSize: '1.6rem', fontWeight: 900, textTransform: 'uppercase' }}>{profile.name || 'Student'}</h2>
          <div style={{ color: 'var(--gold)', fontSize: '0.7rem', marginTop: '4px', fontWeight: 900, letterSpacing: '0.1em' }}>Neural Link: {isGuest ? 'LOCAL ONLY' : 'CLOUD SYNC ACTIVE'}</div>
        </div>

        {isGuest && (
          <div className="glass-panel" style={{ marginBottom: '32px', border: '1px solid var(--gold)', background: 'rgba(255, 191, 0, 0.05)' }}>
            <p style={{ fontSize: '0.8rem', color: '#fff', marginBottom: '12px', textAlign: 'center', fontWeight: 700 }}>Guest mode: progress is local only.</p>
            <button 
              onClick={() => signIn()}
              className="btn-review" 
              style={{ margin: 0, padding: '10px', fontSize: '0.75rem', boxShadow: 'none' }}
            >
              LINK GOOGLE ACCOUNT
            </button>
          </div>
        )}

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginBottom: '32px' }}>
          <div className="glass-panel" style={{ padding: '12px' }}>
            <label className="section-title" style={{ fontSize: '0.55rem' }}>Age</label>
            <input 
              type="text" 
              value={profile.age} 
              onChange={(e) => updateProfile({ age: e.target.value })}
              className="settings-input"
              style={{ marginBottom: 0, padding: '8px', fontSize: '0.85rem' }}
            />
          </div>
          <div className="glass-panel" style={{ padding: '12px' }}>
            <label className="section-title" style={{ fontSize: '0.55rem' }}>Sex</label>
            <input 
              type="text" 
              value={profile.sex} 
              onChange={(e) => updateProfile({ sex: e.target.value })}
              className="settings-input"
              style={{ marginBottom: 0, padding: '8px', fontSize: '0.85rem' }}
            />
          </div>
        </div>

        <div className="glass-panel" style={{ marginBottom: '32px' }}>
          <h3 className="section-title" style={{ fontSize: '0.6rem' }}>Biographical Data (Lore)</h3>
          <div style={{ display: 'flex', gap: '8px', marginBottom: '12px' }}>
            <select 
              value={loreCategory} 
              onChange={(e) => setLoreCategory(e.target.value as LoreCategory)}
              className="sort-select"
              style={{ flex: '0 0 auto', width: '90px', fontSize: '0.75rem', padding: '8px' }}
            >
              <option value="Work">Work</option>
              <option value="Hobbies">Hobbies</option>
              <option value="Pets">Pets</option>
              <option value="Projects">Projects</option>
              <option value="Lifestyle">Lifestyle</option>
            </select>
            <input 
              type="text" 
              value={loreDetail}
              onChange={(e) => setLoreDetail(e.target.value)}
              placeholder="Add lore..."
              className="settings-input"
              style={{ flex: 1, marginBottom: 0, padding: '8px', fontSize: '0.85rem' }}
              onKeyDown={(e) => e.key === 'Enter' && handleAddLore()}
            />
            <button 
              onClick={handleAddLore}
              style={{ background: 'var(--gold)', color: '#000', border: 'none', borderRadius: '2px', padding: '0 12px', fontWeight: 900, fontSize: '0.7rem' }}
            >
              ADD
            </button>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            {lore.map((entry) => (
              <div key={entry.id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: 'rgba(255,255,255,0.03)', padding: '10px', borderRadius: '2px', border: '1px solid var(--border)' }}>
                <div style={{ fontSize: '0.8rem' }}>
                  <span style={{ color: 'var(--gold)', fontWeight: 900, textTransform: 'uppercase', fontSize: '0.6rem', marginRight: '10px' }}>{entry.category}</span>
                  <span style={{ color: '#ccc' }}>{entry.detail}</span>
                </div>
                <button 
                  onClick={() => deleteLore(entry.id)}
                  style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', padding: '4px' }}
                >
                  ✕
                </button>
              </div>
            ))}
          </div>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', marginBottom: '40px' }}>
          <button 
            onClick={() => {
              clearLocalData();
              setUser(null);
              logout();
              onClose();
            }}
            className="btn-danger"
            style={{ 
              textAlign: 'center', 
              padding: '12px', 
              fontSize: '0.8rem',
              letterSpacing: '0.1em'
            }}
          >
            TERMINATE SESSION
          </button>
        </div>
      </div>
    </motion.div>
  );
}

// src/types/mastery.ts
// ─── Status ──────────────────────────────────────────────────────────────────

export const MASTERY_STATUS = {
  NOT_STARTED: 'not_started',
  INTRODUCED: 'introduced',
  PRACTICING: 'practicing',
  CONFIDENT: 'confident',
  MASTERED: 'mastered',
} as const;

export type MasteryStatus = (typeof MASTERY_STATUS)[keyof typeof MASTERY_STATUS];

export const STATUS_META: Record<
  MasteryStatus,
  { emoji: string; label: string; meaning: string }
> = {
  not_started: {
    emoji: '⬜',
    label: 'Not Started',
    meaning: 'Concept has not yet been introduced.',
  },
  introduced: {
    emoji: '🔵',
    label: 'Introduced',
    meaning: 'The word is new to you (0-50 pts).',
  },
  practicing: {
    emoji: '🟡',
    label: 'Practicing',
    meaning: "You're using it, but it's not fluid yet (51-150 pts).",
  },
  confident: {
    emoji: '🟢',
    label: 'Confident',
    meaning: 'You know it well in most contexts (151-400 pts).',
  },
  mastered: {
    emoji: '✅',
    label: 'Mastered',
    meaning:
      'The word is now part of your "mental map" (400+ pts).',
  },
};

// ─── Score → Status derivation ────────────────────────────────────────────────
// Status is derived from confidenceScore; it is never stored independently.
// New thresholds per Requirement 5:
//  0      → not_started (usually 0)
//  1–50   → introduced
//  51–150 → practicing
//  151–400→ confident
//  401+   → mastered

export function scoreToStatus(score: number): MasteryStatus {
  if (score > 400) return 'mastered';
  if (score > 150) return 'confident';
  if (score > 50) return 'practicing';
  if (score > 0) return 'introduced';
  return 'not_started';
}

// Midpoint of each tier's range — used to seed confidenceScore when reading
// legacy cloud data that only has a status field.
export const STATUS_MIDPOINT: Record<MasteryStatus, number> = {
  not_started: 0,
  introduced:  25,
  practicing:  100,
  confident:   275,
  mastered:    450,
};

// ─── Lore & Profile ──────────────────────────────────────────────────────────

export type LoreCategory = 'Work' | 'Hobbies' | 'Pets' | 'Projects' | 'Lifestyle';

export interface LoreEntry {
  id: string;
  category: LoreCategory;
  detail: string;
}

export interface ProgressSnapshot {
  date: string;
  xp: number;
  totalLearned: number;
  streak: number;
}

export interface UserProfile {
  name: string;
  age: string;
  location: string;
  sex: string;
  history: ProgressSnapshot[];
}

export type ReviewVibe = 'chill' | 'deep';

// ─── Grammar Concepts ─────────────────────────────────────────────────────────

export interface GrammarConcept {
  id: string;
  concept: string;
  status: MasteryStatus;
  sessionNotes: string;
}

// ─── Chapters ─────────────────────────────────────────────────────────────────

export interface Chapter {
  id: string;
  title: string;
  order: number;
  // order === 0 is reserved for the Introduction section
  concepts: GrammarConcept[];
}

// ─── Vocabulary ───────────────────────────────────────────────────────────────

export interface VocabWord {
  id: string;
  word: string;
  partOfSpeech: string;
  meanings: string;
  // confidenceScore is the source of truth (0–100).
  // status is derived from it via scoreToStatus() and kept in sync.
  confidenceScore: number;
  status: MasteryStatus;
  useCount: number;
  frequencyRank: number;
  isMasteryCandidate: boolean;
  sessionNotes: string;
}

// ─── Top-level Map ────────────────────────────────────────────────────────────

export interface SavedPhrase {
  id: string;
  tp: string;
  en: string;
  notes: string;
}

export interface MasteryMap {
  studentName: string;
  profileImage: string;
  curriculumLevel: string;
  lastUpdated: string;
  chapters: Chapter[];   // index 0 = Introduction
  vocabulary: VocabWord[];

  // NEW FEATURES
  savedPhrases: (string | SavedPhrase)[];
  currentStreak: number;
  lastActiveDate: string;
}


// ─── Status summary helper type ───────────────────────────────────────────────

export type StatusSummary = Record<MasteryStatus, number>;

