  cursor: pointer;
  position: relative;
  overflow: hidden;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.vocab-card:hover {
  border-color: var(--gold);
  background: rgba(255, 191, 0, 0.05);
}

