/* src/components/PhraseGrid.tsx */
import { useState, useEffect } from 'react';
import { useMasteryStore } from '../store/masteryStore';
import type { MasteryStatus } from '../types/mastery';

interface Props {
  onAskLina: (prompt: string) => void;
  activeFilter: MasteryStatus | null;
  selectedWords: string[];
  focusPhraseId?: string | null;
  clearFocusPhrase?: () => void;
}

const PHRASES = [
  { tp: "ale li pona.", en: "Everything is good." },
  { tp: "ni li lili.", en: "That is small." },
  { tp: "sina wawa.", en: "You are strong." },
  { tp: "pali pona!", en: "Good work!" },
  { tp: "mi pilin ike.", en: "I feel bad." },
  { tp: "sina sona mute.", en: "You are smart." },
  { tp: "sina pona tawa jan.", en: "You are kind." }
];

export default function PhraseGrid({ onAskLina, activeFilter, selectedWords, focusPhraseId, clearFocusPhrase }: Props) {
  const { vocabulary, savedPhrases, updatePhraseNote, deletePhrase } = useMasteryStore();
  const [editingId, setEditingId] = useState<string | null>(null);
  const [noteInput, setNoteInput] = useState('');

  const clean = (w: string) => w.toLowerCase().replace(/[.!?,]/g, '');

  const safeSavedPhrases = savedPhrases || [];

  useEffect(() => {
    if (focusPhraseId) {
      setEditingId(focusPhraseId);
      const target = safeSavedPhrases.find(p => typeof p !== 'string' && p.id === focusPhraseId);
      setNoteInput(target && typeof target !== 'string' ? target.notes : '');
    }
  }, [focusPhraseId, safeSavedPhrases]);

  const normalizedSaved = safeSavedPhrases.map(p => 
    typeof p === 'string' ? { id: p, tp: p, en: 'User Saved Phrase *', notes: '' } : p
  );

  const combined = [
    ...PHRASES.map(p => ({ ...p, isSaved: false, id: p.tp, notes: '' })), 
    ...normalizedSaved.map(p => ({ ...p, isSaved: true }))
  ];

  const filtered = combined.filter(p => {
    if (!p.isSaved) {
      const ws = p.tp.split(' ').map(clean);
      const isKnown = ws.every(w => {
        const v = vocabulary.find(i => i.word === w);
        return v && v.status !== 'not_started';
      });
      if (!isKnown) return false;
    }

    if (selectedWords.length > 0) {
      const ws = p.tp.split(' ').map(clean);
      if (!selectedWords.every(sw => ws.includes(clean(sw)))) return false;
    }

    if (activeFilter && !p.isSaved) {
      const ws = p.tp.split(' ').map(clean);
      if (!ws.some(w => vocabulary.find(i => i.word === w)?.status === activeFilter)) return false;
    }

    return true;
  });

  return (
    <section className="phrase-grid">
      <h2 className="section-title" style={{ marginBottom: '20px' }}>
        {selectedWords.length > 0 ? `SUGGESTED COMBINATIONS` : 'PRACTICE PHRASES'}
      </h2>
      <div style={{ display: 'grid', gap: '12px', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))' }}>
        {filtered.map((p) => {
          const words = p.tp.split(' ');
          return (
            <div key={p.id} style={{ background: p.isSaved ? '#0f172a' : '#111', padding: '16px', borderRadius: '8px', border: p.isSaved ? '1px solid #3b82f6' : '1px solid #333' }}>
              <div onClick={() => onAskLina(`toki jan Lina! Let's practice: "${p.tp}"`)} style={{ cursor: 'pointer' }}>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px', marginBottom: '8px' }}>
                  {words.map((w, idx) => {
                    const cleanW = clean(w);
                    const vocab = vocabulary.find(v => v.word === cleanW);
                    const meaning = vocab?.meanings?.split(',')[0].trim() || '';
                    return (
                      <div key={idx} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                        <div style={{ fontSize: '0.55rem', color: '#666', textTransform: 'uppercase', fontWeight: 700, marginBottom: '1px' }}>{meaning}</div>
                        <div style={{ fontWeight: 'bold', fontSize: '1.05rem', color: p.isSaved ? '#60a5fa' : '#fff' }}>{w}</div>
                      </div>
                    );
                  })}
                  {p.isSaved && <span style={{ color: '#60a5fa', fontWeight: 'bold', marginLeft: '4px' }}>*</span>}
                </div>
                <div style={{ fontSize: '0.8rem', color: p.isSaved ? '#94a3b8' : '#777', fontStyle: 'italic' }}>{p.en}</div>
              </div>
              {p.isSaved && (
                <div style={{ marginTop: '10px', paddingTop: '10px', borderTop: '1px solid #1e293b' }}>
                  {p.notes && <div style={{ fontSize: '0.8rem', color: '#cbd5e1', marginBottom: '8px', padding: '6px', background: '#1e293b', borderRadius: '4px' }}>📝 {p.notes}</div>}
                  <div style={{ display: 'flex', gap: '8px' }}>
                    <button onClick={() => { setEditingId(p.id); setNoteInput(p.notes); }} className="btn-toggle" style={{ padding: '4px 8px', fontSize: '0.65rem', width: 'auto' }}>
                      {p.notes ? 'EDIT NOTE' : '+ NOTE'}
                    </button>
                    <button onClick={() => { if(window.confirm('Delete this saved phrase?')) deletePhrase(p.id); }} className="btn-toggle" style={{ padding: '4px 8px', fontSize: '0.65rem', width: 'auto', background: '#7f1d1d' }}>
                      DELETE
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {editingId && (
        <div className="drawer-backdrop" onClick={() => { setEditingId(null); clearFocusPhrase?.(); }} style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 5000 }}>
          <div onClick={e => e.stopPropagation()} style={{ background: '#111', padding: '20px', borderRadius: '12px', width: '90%', maxWidth: '400px', border: '1px solid #444', boxShadow: '0 10px 30px rgba(0,0,0,0.8)' }}>
            <h3 style={{ color: '#fff', marginBottom: '15px', marginTop: 0 }}>Phrase Note</h3>
            <textarea value={noteInput} onChange={e => setNoteInput(e.target.value)} placeholder="Add context to this phrase..." style={{ width: '100%', height: '100px', background: '#222', color: '#fff', border: '1px solid #444', borderRadius: '8px', padding: '10px', marginBottom: '15px', resize: 'none', outline: 'none' }} autoFocus />
            <div style={{ display: 'flex', gap: '10px' }}>
              <button onClick={() => { updatePhraseNote(editingId, noteInput); setEditingId(null); clearFocusPhrase?.(); }} className="btn-review" style={{ margin: 0, flex: 2 }}>SAVE</button>
              <button onClick={() => { setEditingId(null); clearFocusPhrase?.(); }} className="btn-toggle" style={{ flex: 1 }}>CANCEL</button>
            </div>
          </div>
        </div>
      )}
    </section>
  );
}

/* src/components/ProgressSummary.tsx */
import { useMasteryStore } from '../store/masteryStore';
import type { MasteryStatus } from '../types/mastery';

interface Props {
  activeFilter: MasteryStatus | null;
  onFilterClick: (status: MasteryStatus | null) => void;
}

export default function ProgressSummary({ activeFilter, onFilterClick }: Props) {
  const _vocab = useMasteryStore((s) => s.vocabulary);
  const getStatusSummary = useMasteryStore((s) => s.getStatusSummary);
  const summary = getStatusSummary();

  const statusItems: { status: MasteryStatus; label: string; emoji: string; color: string; glow: string }[] = [
    { status: 'not_started', label: 'NOT STARTED', emoji: '⬜', color: '#9ca3af', glow: 'rgba(156,163,175,0.5)' },
    { status: 'introduced',  label: 'INTRODUCED',  emoji: '🔵', color: '#3b82f6', glow: 'rgba(59,130,246,0.6)'  },
    { status: 'practicing',  label: 'PRACTICING',  emoji: '🟡', color: '#f59e0b', glow: 'rgba(245,158,11,0.6)'  },
    { status: 'confident',   label: 'CONFIDENT',   emoji: '🟢', color: '#16a34a', glow: 'rgba(22,163,74,0.6)'   },
    { status: 'mastered',    label: 'MASTERED',    emoji: '✅', color: '#22c55e', glow: 'rgba(34,197,94,0.65)'  },
  ];

  return (
    <div style={{ background: '#111', borderRadius: '16px', padding: '14px', border: '1px solid #222', marginBottom: '14px' }}>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '6px' }}>
        {statusItems.map((item) => {
          const isActive = activeFilter === item.status;
          const isDimmed = activeFilter !== null && !isActive;
          const shouldGlow = activeFilter === null || isActive;

          return (
            <button
              key={item.status}
              onClick={() => onFilterClick(isActive ? null : item.status)}
              style={{
                background: isActive ? `${item.color}22` : '#0d0d0d',
                border: isActive ? `2px solid ${item.color}` : `1px solid ${item.color}44`,
                padding: '10px 4px 8px',
                borderRadius: '12px',
                cursor: 'pointer',
                transition: 'all 0.25s ease',
                opacity: isDimmed ? 0.3 : 1,
                boxShadow: shouldGlow
                  ? `0 0 14px ${item.glow}, 0 0 4px ${item.glow}`
                  : 'none',
                transform: isActive ? 'scale(1.06)' : 'scale(1)',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: '4px',
              }}
            >
              <span style={{ fontSize: '1.1rem', lineHeight: 1 }}>{item.emoji}</span>
              <span style={{ fontSize: '1rem', fontWeight: 'bold', color: item.color, lineHeight: 1 }}>
                {summary[item.status]}
              </span>
              <span style={{
                fontSize: '0.48rem',
                color: isActive ? item.color : `${item.color}99`,
                fontWeight: '700',
                letterSpacing: '0.04em',
              }}>
                {item.label}
              </span>
            </button>
          );
        })}
      </div>
    </div>
  );
}

/* src/store/masteryStore.ts */
import { db } from '../services/firebase';
import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { doc, setDoc, onSnapshot, getDoc } from 'firebase/firestore';
import type { Unsubscribe } from 'firebase/firestore';
import type { MasteryStatus, VocabWord, StatusSummary, SavedPhrase, UserProfile, LoreEntry, ReviewVibe, LoreCategory } from '../types/mastery';
import { scoreToStatus, STATUS_MIDPOINT } from '../types/mastery';
import { initialMasteryMap } from '../data/initialMasteryMap';

interface Concept {
  id: string;
  title: string;
  status: MasteryStatus;
  sessionNotes: string;
}

function toFullVocabWord(v: { word: string; status: MasteryStatus; sessionNotes: string; frequencyRank?: number }): VocabWord {
  return {
    id: v.word,
    word: v.word,
    partOfSpeech: '',
    meanings: '',
    confidenceScore: STATUS_MIDPOINT[v.status],
    status: v.status,
    useCount: 0,
    frequencyRank: v.frequencyRank ?? 999,
    isMasteryCandidate: false,
    sessionNotes: v.sessionNotes,
  };
}

const mappedVocabulary: VocabWord[] = initialMasteryMap.initialVocabulary.map(toFullVocabWord);

interface MasteryActions {
  applyScoreDeltas: (deltas: { wordId: string; delta: number }[]) => void;
  updateVocabStatus: (wordIdOrText: string, status: MasteryStatus) => void;
  cycleWordStatus: (wordId: string) => void;
  updateConceptStatus: (id: string, status: MasteryStatus) => void;
  setLastUpdated: (date: string) => void;
  savePhrase: (phrase: string | SavedPhrase) => void;
  recordActivity: () => void;
  setStudentName: (name: string) => void;
  updateProfile: (profile: Partial<UserProfile>) => void;
  addLore: (category: LoreCategory, detail: string) => void;
  deleteLore: (id: string) => void;
  setReviewVibe: (vibe: ReviewVibe) => void;
  setProfileImage: (url: string) => void;
  updatePhraseNote: (id: string, notes: string) => void;
  deletePhrase: (id: string) => void;
  resetAsNewUser: () => void;
  resetProfileAndRunSetup: () => void;
  randomizeVocab: () => void;
  masterAllVocab: () => void;
  clearLocalData: () => void;
  syncFromCloud: (userId: string, initialName?: string, initialProfileImage?: string) => Promise<Unsubscribe | void>;
  syncToCloud: (userId?: string) => Promise<void>;
  getStatusSummary: () => StatusSummary & { xp: number; level: number; rankTitle: string };
  setActiveLesson: (curriculumId: string, moduleId: string) => void;
  setHasCompletedSetup: (val: boolean) => void;
}

interface MasteryState {
  userId: string | null;
  studentName: string;
  profile: UserProfile;
  lore: LoreEntry[];
  reviewVibe: ReviewVibe;
  profileImage: string;
  lastUpdated: string;
  vocabulary: VocabWord[];
  concepts: Concept[];
  curriculums: typeof initialMasteryMap.curriculums;
  activeCurriculumId: string | null;
  activeModuleId: string | null;
  savedPhrases: (string | SavedPhrase)[];
  currentStreak: number;
  lastActiveDate: string;
  hasCompletedSetup: boolean;
}

type MasteryStore = MasteryState & MasteryActions;

const XP_MAP = { not_started: 0, introduced: 10, practicing: 25, confident: 50, mastered: 100 };
const STATUS_ORDER: MasteryStatus[] = ['not_started', 'introduced', 'practicing', 'confident', 'mastered'];
const clamp = (n: number, min: number, max: number) => Math.min(max, Math.max(min, n));

export const useMasteryStore = create<MasteryStore>()(
  persist(
    (set, get) => ({
      userId: null,
      studentName: 'Anthony',
      profile: { name: 'Anthony', age: '', location: '', sex: '', history: [] },
      lore: [],
      reviewVibe: 'chill',
      profileImage: '',
      lastUpdated: '',
      vocabulary: mappedVocabulary,
      concepts: initialMasteryMap.initialConcepts,
      curriculums: initialMasteryMap.curriculums,
      activeCurriculumId: null,
      activeModuleId: null,
      savedPhrases: [],
      currentStreak: 0,
      lastActiveDate: '',
      hasCompletedSetup: false,

      setHasCompletedSetup: (val) => { set({ hasCompletedSetup: val }); void get().syncToCloud(); },

      applyScoreDeltas: (deltas) => {
        set((state) => ({
          vocabulary: state.vocabulary.map((w) => {
            const d = deltas.find(
              (delta) =>
                delta.wordId === w.id ||
                delta.wordId.toLowerCase() === w.word.toLowerCase()
            );
            if (!d) return w;
            const newScore = clamp((w.confidenceScore ?? 0) + d.delta, 0, 500);
            return {
              ...w,
              confidenceScore: newScore,
              status: scoreToStatus(newScore),
              useCount: (w.useCount ?? 0) + 1,
            };
          }),
        }));
        get().recordActivity();
        void get().syncToCloud();
      },

      updateVocabStatus: (wordIdOrText, status) => {
        set((state) => ({
          vocabulary: state.vocabulary.map((w) => {
            if (w.id !== wordIdOrText && w.word.toLowerCase() !== wordIdOrText.toLowerCase()) return w;
            const targetScore = STATUS_MIDPOINT[status];
            return { ...w, confidenceScore: targetScore, status };
          }),
        }));
        get().recordActivity();
        void get().syncToCloud();
      },

      cycleWordStatus: (wordId) => {
        set((state) => ({
          vocabulary: state.vocabulary.map((w) => {
            if (w.id !== wordId) return w;
            const currentIndex = STATUS_ORDER.indexOf(w.status);
            const nextStatus = STATUS_ORDER[(currentIndex + 1) % STATUS_ORDER.length];
            const targetScore = STATUS_MIDPOINT[nextStatus];
            return { ...w, confidenceScore: targetScore, status: nextStatus };
          }),
        }));
        get().recordActivity();
        void get().syncToCloud();
      },

      updateConceptStatus: (id, status) => {
        set((state) => ({
          concepts: state.concepts.map((c) =>
            c.id === id ? { ...c, status } : c
          ),
        }));
        void get().syncToCloud();
      },

      savePhrase: (phrase) => {
        set((state) => {
          const key = typeof phrase === 'string' ? phrase : phrase.tp;
          const already = state.savedPhrases.some(p =>
            typeof p === 'string' ? p === key : p.tp === key
          );
          if (already) return state;
          return { savedPhrases: [...state.savedPhrases, phrase] };
        });
        void get().syncToCloud();
      },

      recordActivity: () => {
        const today = new Date().toDateString();
        const lastDate = get().lastActiveDate;

        let newStreak = get().currentStreak;
        let streakChanged = false;

        if (lastDate !== today) {
          const yesterday = new Date();
          yesterday.setDate(yesterday.getDate() - 1);
          if (lastDate === yesterday.toDateString()) {
            newStreak += 1;
          } else {
            newStreak = 1;
          }
          streakChanged = true;
          set({ currentStreak: newStreak, lastActiveDate: today });
        }

        if (streakChanged) {
          const summary = get().getStatusSummary();
          const totalLearned = summary.introduced + summary.practicing + summary.confident + summary.mastered;
          const snapshot = {
            date: today,
            xp: summary.xp,
            totalLearned,
            streak: newStreak
          };

          set(state => ({
            profile: {
              ...state.profile,
              history: [...(state.profile.history || []), snapshot]
            }
          }));
        }
      },

      setStudentName: (name) => { set({ studentName: name }); get().updateProfile({ name }); },
      updateProfile: (profile) => { set((state) => ({ profile: { ...state.profile, ...profile } })); void get().syncToCloud(); },
      addLore: (category, detail) => { 
        set((state) => ({ lore: [...state.lore, { id: crypto.randomUUID(), category, detail }] })); 
        void get().syncToCloud(); 
      },
      deleteLore: (id) => { 
        set((state) => ({ lore: state.lore.filter(l => l.id !== id) })); 
        void get().syncToCloud(); 
      },
      setReviewVibe: (vibe) => { set({ reviewVibe: vibe }); },
      setProfileImage: (url) => { set({ profileImage: url }); void get().syncToCloud(); },

      updatePhraseNote: (id, notes) => {
        set((state) => ({
          savedPhrases: state.savedPhrases.map(p => {
            if (typeof p === 'string') return p === id ? { id, tp: p, en: 'User Saved Phrase *', notes } : p;
            return p.id === id ? { ...p, notes } : p;
          })
        }));
        void get().syncToCloud();
      },

      deletePhrase: (id) => {
        set((state) => ({
          savedPhrases: state.savedPhrases.filter(p =>
            typeof p === 'string' ? p !== id : p.id !== id
          )
        }));
        void get().syncToCloud();
      },

      resetAsNewUser: () => {
        set({
          studentName: '',
          profile: { name: '', age: '', location: '', sex: '', history: [] },
          lore: [],
          reviewVibe: 'chill',
          profileImage: '',
          savedPhrases: [],
          currentStreak: 0,
          lastActiveDate: '',
          vocabulary: mappedVocabulary,
          concepts: initialMasteryMap.initialConcepts,
          activeCurriculumId: null,
          activeModuleId: null,
          hasCompletedSetup: false,
        });
        void get().syncToCloud();
      },

      resetProfileAndRunSetup: () => {
        set({
          studentName: '',
          profile: { name: '', age: '', location: '', sex: '', history: [] },
          lore: [],
          profileImage: '',
          hasCompletedSetup: false,
        });
        void get().syncToCloud();
      },

      randomizeVocab: () => {
        set((state) => ({
          vocabulary: state.vocabulary.map(w => {
            const score = Math.floor(Math.random() * 451);
            return { ...w, confidenceScore: score, status: scoreToStatus(score) };
          })
        }));
        void get().syncToCloud();
      },

      masterAllVocab: () => {
        set((state) => ({
          vocabulary: state.vocabulary.map(w => ({ ...w, confidenceScore: 450, status: 'mastered' as MasteryStatus }))
        }));
        void get().syncToCloud();
      },

      clearLocalData: () => {
        set({
          userId: null,
          studentName: 'Anthony',
          profile: { name: 'Anthony', age: '', location: '', sex: '' },
          lore: [],
          reviewVibe: 'chill',
          profileImage: '',
          savedPhrases: [],
          currentStreak: 0,
          lastActiveDate: '',
          vocabulary: mappedVocabulary,
          concepts: initialMasteryMap.initialConcepts,
          activeCurriculumId: null,
          activeModuleId: null,
          hasCompletedSetup: false,
        });
      },

      setLastUpdated: (date) => set({ lastUpdated: date }),

      getStatusSummary: () => {
        const { vocabulary } = get();
        const summary = { not_started: 0, introduced: 0, practicing: 0, confident: 0, mastered: 0, xp: 0 };
        for (const word of vocabulary) {
          summary[word.status]++;
          summary.xp += XP_MAP[word.status];
        }
        const level = Math.floor(summary.xp / 500) + 1;
        let rankTitle = 'nimi lili';
        if (level >= 5) rankTitle = 'jan pi toki pona';
        if (level >= 10) rankTitle = 'jan sona';
        return { ...summary, level, rankTitle };
      },

      setActiveLesson: (curriculumId, moduleId) =>
        set({ activeCurriculumId: curriculumId, activeModuleId: moduleId }),

      syncToCloud: async (explicitUserId) => {
        const { vocabulary, concepts, lastUpdated, studentName, profile, lore, profileImage, savedPhrases, currentStreak, lastActiveDate, userId, hasCompletedSetup } = get();
        const targetId = explicitUserId || userId;
        if (!targetId || targetId === 'guest_user') return;

        try {
          await setDoc(doc(db, 'users', targetId), {
            vocabulary, concepts, lastUpdated, studentName, profile, lore, profileImage,
            savedPhrases, currentStreak, lastActiveDate, hasCompletedSetup
          }, { merge: true });
        } catch (err) {
          console.error('Firebase Sync Error:', err);
        }
      },

      syncFromCloud: async (uid: string, initialName?: string, initialProfileImage?: string) => {
        set({ userId: uid });
        if (uid === 'guest_user') return;

        const userDocRef = doc(db, 'users', uid);

        try {
          const docSnap = await getDoc(userDocRef);

          if (!docSnap.exists()) {
            // New user or no cloud data
            if (initialName && (get().studentName === 'Anthony' || !get().studentName)) {
              set({ studentName: initialName });
              get().updateProfile({ name: initialName });
            }
            if (initialProfileImage && !get().profileImage) {
              set({ profileImage: initialProfileImage });
            }

            const { vocabulary } = get();
            const isFresh = vocabulary.every(w => w.status === 'not_started');
            if (!isFresh) {
              console.log('Migrating local progress to Firestore...');
              await get().syncToCloud(uid);
            }
          }
        } catch (err) {
          console.error('Error checking for migration:', err);
        }

        return onSnapshot(userDocRef, (snapshot) => {
          if (!snapshot.exists()) return;
          const data = snapshot.data();

          const vocabulary = (data.vocabulary || mappedVocabulary).map(
            (w: any) => {
              const base = mappedVocabulary.find(iv => iv.word === w.word);
              const useCount = typeof w.useCount === 'number' ? w.useCount : 0;
              const frequencyRank = typeof w.frequencyRank === 'number' ? w.frequencyRank : (base?.frequencyRank ?? 999);

              if (typeof w.confidenceScore === 'number') return { ...w, useCount, frequencyRank };
              const status: MasteryStatus = w.status || 'not_started';
              return { ...w, confidenceScore: STATUS_MIDPOINT[status], useCount, frequencyRank };
            }
          );

          set({
            vocabulary,
            concepts: data.concepts || initialMasteryMap.initialConcepts,
            lastUpdated: data.lastUpdated || '',
            studentName: data.studentName || 'Anthony',
            profile: data.profile || { name: data.studentName || 'Anthony', age: '', location: '', sex: '' },
            lore: data.lore || [],
            profileImage: data.profileImage || '',
            savedPhrases: data.savedPhrases || [],
            currentStreak: data.currentStreak || 0,
            lastActiveDate: data.lastActiveDate || '',
            hasCompletedSetup: data.hasCompletedSetup || false,
          });
        });
      },
    }),
    { 
      name: 'tp-tutor-mastery',
      partialize: (state) => {
        // eslint-disable-next-line @typescript-eslint/no-unused-vars
        const { userId, ...rest } = state;
        return rest;
      }
    }
  )
);

/* src/components/VocabCard.tsx */
import { useRef } from 'react';
import type { VocabWord, MasteryStatus } from '../types/mastery';
import { useMasteryStore } from '../store/masteryStore';
import { soundService } from '../services/soundService';

// Tier boundaries matching scoreToStatus() thresholds.
const TIER_RANGES: Record<MasteryStatus, [number, number]> = {
  not_started: [0,  0],
  introduced:  [1, 50],
  practicing:  [51, 150],
  confident:   [151, 400],
  mastered:    [401, 500],
};

const RING_COLOR: Record<MasteryStatus, string> = {
  not_started: '#374151',
  introduced:  '#1d4ed8',
  practicing:  '#92400e',
  confident:   '#16a34a',
  mastered:    '#22c55e',
};

// How far through the current tier the score is, as a 0–1 fraction.
function progressWithinTier(score: number, status: MasteryStatus): number {
  const [lo, hi] = TIER_RANGES[status];
  if (hi === lo) return 1;
  return Math.min(1, Math.max(0, (score - lo) / (hi - lo)));
}

interface Props {
  word: VocabWord;
  onLongPress?: (word: VocabWord) => void;
  onClick?: (word: VocabWord) => void;
}

export default function VocabCard({ word, onLongPress, onClick }: Props) {
  const { cycleWordStatus } = useMasteryStore();
  const score  = word.confidenceScore ?? 0;
  const status = word.status;
  const color  = RING_COLOR[status];
  const fill   = progressWithinTier(score, status);

  const lastTapRef = useRef<number>(0);
  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isLongPress = useRef(false);

  const handlePointerDown = (e: React.PointerEvent) => {
    isLongPress.current = false;
    longPressTimer.current = setTimeout(() => {
      isLongPress.current = true;
      soundService.playBlip(523.25, 'sine', 0.05);
      onLongPress?.(word);
    }, 500);
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }

    if (isLongPress.current) {
      isLongPress.current = false;
      return;
    }

    const now = Date.now();
    if (now - lastTapRef.current < 300) {
      // Secret Double Tap
      cycleWordStatus(word.id);
      lastTapRef.current = 0;
    } else {
      lastTapRef.current = now;
      onClick?.(word);
    }
  };

  const handlePointerCancel = () => {
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }
  };

  return (
    <div
      className={`vocab-card vocab-card--${status}`}
      style={{ position: 'relative', touchAction: 'none' }}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerCancel={handlePointerCancel}
    >
      {/* Confidence ring */}
      <svg
        aria-hidden
        style={{
          position:  'absolute',
          inset:     -1,
          width:     'calc(100% + 2px)',
          height:    'calc(100% + 2px)',
          borderRadius: '8px',
          overflow:  'visible',
          pointerEvents: 'none',
        }}
        viewBox={`0 0 100 100`}
        preserveAspectRatio="none"
      >
        <rect
          x={1.5} y={1.5}
          width={97} height={97}
          rx={8} ry={8}
          fill="none"
          stroke={color}
          strokeWidth={3}
          strokeOpacity={0.15}
        />
        <circle
          cx={50} cy={50} r={48.5}
          fill="none"
          stroke={color}
          strokeWidth={3}
          strokeOpacity={0.85}
          strokeLinecap="round"
          strokeDasharray={`${2 * Math.PI * 48.5 * fill} ${2 * Math.PI * 48.5 * (1 - fill)}`}
          transform={`rotate(-90 50 50)`}
          style={{ transition: 'stroke-dasharray 0.4s ease' }}
        />
      </svg>

      <div className="vocab-card__word">{word.word}</div>
      <div className="vocab-card__pos">{word.partOfSpeech}</div>
    </div>
  );
}

