             <ChatSession isActive={true} onEndSession={() => setExpandedTile(null)} isSandboxMode={isSandboxMode} />
          </ModalWrapper>
        )}
      </AnimatePresence>
    </div>
  );
}

function ModalWrapper({ children, onClose }: { children: React.ReactNode, onClose: () => void }) {
  return (
    <motion.div
